package com.stockmind.application.risk;
import java.math.BigDecimal;import java.time.LocalDate;import java.util.List;
public record SupplementalRiskSnapshot(LocalDate asOf,boolean currentOnly,BigDecimal lockupReleaseRatioNext30d,BigDecimal lockupReleaseRatioNext90d,BigDecimal marginBalanceChange20d,BigDecimal shareholderCountChangeRatio,BigDecimal blockTradeAverageDiscountRatio,List<String>sources,List<String>limitations){public SupplementalRiskSnapshot{sources=sources==null?List.of():List.copyOf(sources);limitations=limitations==null?List.of():List.copyOf(limitations);}/** Creates an explicit missing snapshot so absence is not interpreted as zero risk. */public static SupplementalRiskSnapshot unavailable(LocalDate d,String reason){return new SupplementalRiskSnapshot(d,true,null,null,null,null,null,List.of(),List.of(reason));}}
